import logo from './logo.svg';
import React, { useState } from 'react';
import './App.css';

function App() {
  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");
  const [tag, setTag] = useState("");
  const [showForm, setShowForm] = useState(true);

  const headleClick = () => {
    console.log('このアプリはメモ管理用のReactアプリです');
  };

  const toggleForm = () => {
    setShowForm(!showForm);
  };

  // --- スタイル定義 ---
  const styles = {
    formContainer: {
      marginTop: '20px',
      padding: '20px',
      border: '1px solid #ccc',
      borderRadius: '8px'
    },
    inputGroup: {
      marginBottom: '10px',
      textAlign: 'left'
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        {/* --- アプリ概要エリア --- */}
        <h1>メモ管理アプリ</h1>
        <p>メモの作成と管理が可能なアプリです</p>
        <button onClick={headleClick} style={{ padding: '10px', cursor: 'pointer' }}>
          説明用ボタン
        </button>

        <hr />

        {/* --- フォーム切り替えエリア --- */}
        <button onClick={toggleForm}>
          {showForm ? 'フォームの非表示' : 'フォームの表示'}
        </button>

        {showForm && (
          <div style={styles.formContainer}>
            {/* タイトル入力 */}
            <div style={styles.inputGroup}>
              <label>タイトル：</label>
              <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="タイトルを入力"
              />
            </div>

            {/* 内容入力 */}
            <div style={styles.inputGroup}>
              <label>内容：</label>
              <textarea
                value={content}
                onChange={(e) => setContent(e.target.value)}
                placeholder="内容を入力"
              />
            </div>

            {/* タグ入力 */}
            <div style={styles.inputGroup}>
              <label>タグ：</label>
              <input
                type="text"
                value={tag}
                onChange={(e) => setTag(e.target.value)}
                placeholder="タグを入力"
              />
            </div>
          </div>
        )}
      </header>
    </div>
  );
}

export default App;
